'use client';

import { useState, useCallback, useRef } from 'react';
import { parseExcelFile } from '@/lib/excel-parser';
import { supabase } from '@/lib/supabase';
import { useFilters } from '@/contexts/FilterContext';
import type { StoreMonthRecord, UploadRecord } from '@/lib/types';

export default function FileUploader() {
  const [isDragOver, setIsDragOver] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [preview, setPreview] = useState<StoreMonthRecord[] | null>(null);
  const [parseErrors, setParseErrors] = useState<string[]>([]);
  const [uploadResult, setUploadResult] = useState<{ success: boolean; message: string } | null>(null);
  const [fileName, setFileName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { refreshData } = useFilters();

  const handleFile = useCallback(async (file: File) => {
    setUploadResult(null);
    setFileName(file.name);

    const buffer = await file.arrayBuffer();
    const result = parseExcelFile(buffer, file.name);

    setParseErrors(result.errors);
    setPreview(result.records);

    if (result.records.length === 0 && result.errors.length > 0) {
      setUploadResult({ success: false, message: `Parse failed: ${result.errors.join(', ')}` });
    }
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
    const file = e.dataTransfer.files[0];
    if (file && (file.name.endsWith('.xlsx') || file.name.endsWith('.xls'))) {
      handleFile(file);
    }
  }, [handleFile]);

  const handleFileInput = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  }, [handleFile]);

  const handleCommit = useCallback(async () => {
    if (!preview || preview.length === 0) return;
    setIsUploading(true);
    setUploadResult(null);

    try {
      // Create upload record
      const { data: uploadData, error: uploadError } = await supabase
        .from('uploads')
        .insert({ filename: fileName, status: 'pending' })
        .select('id')
        .single();

      if (uploadError) throw uploadError;
      const uploadId = uploadData.id;

      // Upsert records with upload_id
      const recordsWithUploadId = preview.map(r => ({
        ...r,
        upload_id: uploadId,
      }));

      const { error: upsertError } = await supabase
        .from('fact_store_month')
        .upsert(recordsWithUploadId, {
          onConflict: 'store,year,month',
          ignoreDuplicates: false,
        });

      if (upsertError) throw upsertError;

      // Update upload status
      await supabase
        .from('uploads')
        .update({
          status: 'success',
          rows_inserted: preview.length,
        })
        .eq('id', uploadId);

      setUploadResult({
        success: true,
        message: `Successfully uploaded ${preview.length} records from "${fileName}"`,
      });
      setPreview(null);
      await refreshData();
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Unknown error';
      setUploadResult({ success: false, message: `Upload failed: ${msg}` });
    } finally {
      setIsUploading(false);
    }
  }, [preview, fileName, refreshData]);

  return (
    <div>
      {/* Drop Zone */}
      <div
        className={`upload-zone${isDragOver ? ' dragover' : ''}`}
        onDragOver={e => { e.preventDefault(); setIsDragOver(true); }}
        onDragLeave={() => setIsDragOver(false)}
        onDrop={handleDrop}
        onClick={() => fileInputRef.current?.click()}
      >
        <div className="upload-zone-icon">≡ƒôè</div>
        <div className="upload-zone-text">
          Drop your Excel file here or click to browse
        </div>
        <div className="upload-zone-hint">
          Supports .xlsx files with the standard template format
        </div>
        <input
          ref={fileInputRef}
          type="file"
          accept=".xlsx,.xls"
          onChange={handleFileInput}
          style={{ display: 'none' }}
        />
      </div>

      {/* Parse Errors */}
      {parseErrors.length > 0 && (
        <div className="card mt-24" style={{ borderColor: 'var(--accent-danger)' }}>
          <div className="card-title" style={{ color: 'var(--accent-danger)' }}>Parse Warnings</div>
          <ul style={{ paddingLeft: 20, fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
            {parseErrors.map((err, i) => (
              <li key={i}>{err}</li>
            ))}
          </ul>
        </div>
      )}

      {/* Preview Table */}
      {preview && preview.length > 0 && (
        <div className="mt-24">
          <div className="flex-between mb-24">
            <div>
              <h3 style={{ fontSize: '1rem', fontWeight: 600 }}>
                Preview ΓÇö {preview.length} records from &quot;{fileName}&quot;
              </h3>
              <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginTop: 4 }}>
                Existing records with the same Store + Year + Month will be replaced.
              </p>
            </div>
            <button
              className="btn btn-primary"
              onClick={handleCommit}
              disabled={isUploading}
            >
              {isUploading ? 'Uploading...' : `Upload ${preview.length} Records`}
            </button>
          </div>

          <div className="data-table-container">
            <div className="data-table-wrapper">
              <table className="data-table">
                <thead>
                  <tr>
                    <th>Store</th>
                    <th>Concept</th>
                    <th>Region</th>
                    <th>Type</th>
                    <th>Year</th>
                    <th>Month</th>
                    <th>Sales</th>
                    <th>EBITDA</th>
                    <th>FCFF</th>
                  </tr>
                </thead>
                <tbody>
                  {preview.slice(0, 50).map((r, i) => (
                    <tr key={i}>
                      <td>{r.store}</td>
                      <td>{r.concept}</td>
                      <td>{r.region}</td>
                      <td>{r.store_type}</td>
                      <td className="numeric">{r.year}</td>
                      <td className="numeric">{r.month}</td>
                      <td className="numeric">{r.sales?.toLocaleString('en-US', { style: 'currency', currency: 'EUR', maximumFractionDigits: 0 })}</td>
                      <td className={`numeric ${r.ebitda >= 0 ? 'cell-positive' : 'cell-negative'}`}>
                        {r.ebitda?.toLocaleString('en-US', { style: 'currency', currency: 'EUR', maximumFractionDigits: 0 })}
                      </td>
                      <td className={`numeric ${r.fcff >= 0 ? 'cell-positive' : 'cell-negative'}`}>
                        {r.fcff?.toLocaleString('en-US', { style: 'currency', currency: 'EUR', maximumFractionDigits: 0 })}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {preview.length > 50 && (
                <div style={{ padding: 16, textAlign: 'center', color: 'var(--text-muted)', fontSize: '0.85rem' }}>
                  Showing first 50 of {preview.length} records
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Upload Result */}
      {uploadResult && (
        <div
          className="card mt-24"
          style={{
            borderColor: uploadResult.success ? 'var(--accent-primary)' : 'var(--accent-danger)',
            background: uploadResult.success ? 'var(--accent-primary-dim)' : 'var(--accent-danger-dim)',
          }}
        >
          <p style={{ fontSize: '0.9rem', fontWeight: 500 }}>
            {uploadResult.success ? 'Γ£ô' : 'Γ£ù'} {uploadResult.message}
          </p>
        </div>
      )}
    </div>
  );
}

'use client';

import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import type { FilterState, PeriodBasis, StoreMonthRecord } from '@/lib/types';
import { supabase } from '@/lib/supabase';

interface FilterContextValue {
  filters: FilterState;
  setFilters: React.Dispatch<React.SetStateAction<FilterState>>;
  updateFilter: <K extends keyof FilterState>(key: K, value: FilterState[K]) => void;
  clearFilters: () => void;
  // Available dimension values (from data)
  availableYears: number[];
  availableStores: string[];
  availableConcepts: string[];
  availableRegions: string[];
  availableStoreTypes: string[];
  availableLocations: string[];
  availableLegalEntities: string[];
  // All raw data
  allData: StoreMonthRecord[];
  filteredData: StoreMonthRecord[];
  isLoading: boolean;
  refreshData: () => Promise<void>;
}

const defaultFilters: FilterState = {
  periodBasis: 'monthly',
  year: null,
  month: null,
  stores: [],
  concepts: [],
  regions: [],
  storeTypes: [],
  locations: [],
  legalEntities: [],
  ebitdaSign: 'all',
  fcffSign: 'all',
  quartile: 'all',
  salesRange: null,
  ebitdaPctRange: null,
  staffPctRange: null,
  rawMaterialsPctRange: null,
  ticketsRange: null,
  avgTicketRange: null,
};

const FilterContext = createContext<FilterContextValue | null>(null);

export function FilterProvider({ children }: { children: React.ReactNode }) {
  const [filters, setFilters] = useState<FilterState>(defaultFilters);
  const [allData, setAllData] = useState<StoreMonthRecord[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Fetch all data from Supabase
  const refreshData = useCallback(async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('fact_store_month')
        .select('*')
        .order('year', { ascending: true })
        .order('month', { ascending: true })
        .limit(100000);

      if (error) throw error;
      setAllData((data as StoreMonthRecord[]) || []);

      // Auto-set year and month to latest available if not set
      if (data && data.length > 0) {
        const maxYear = Math.max(...data.map((d: StoreMonthRecord) => d.year));
        const maxMonth = Math.max(
          ...data.filter((d: StoreMonthRecord) => d.year === maxYear).map((d: StoreMonthRecord) => d.month)
        );
        setFilters(prev => ({
          ...prev,
          year: prev.year ?? maxYear,
          month: prev.month ?? maxMonth,
        }));
      }
    } catch (err) {
      console.error('Failed to fetch data:', err);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    refreshData();
  }, [refreshData]);

  // Extract available dimension values (cascading)
  const availableYears = React.useMemo(() => [...new Set(allData.map(d => d.year))].sort(), [allData]);
  const availableLocations = React.useMemo(() => [...new Set(allData.map(d => d.location))].sort(), [allData]);
  const availableLegalEntities = React.useMemo(() => [...new Set(allData.map(d => d.legal_entity))].sort(), [allData]);

  const availableStores = React.useMemo(() => {
    const valid = allData.filter(d => 
      (filters.concepts.length === 0 || filters.concepts.includes(d.concept)) &&
      (filters.regions.length === 0 || filters.regions.includes(d.region)) &&
      (filters.storeTypes.length === 0 || filters.storeTypes.includes(d.store_type))
    );
    return [...new Set(valid.map(d => d.store))].sort();
  }, [allData, filters.concepts, filters.regions, filters.storeTypes]);

  const availableConcepts = React.useMemo(() => {
    const valid = allData.filter(d => 
      (filters.stores.length === 0 || filters.stores.includes(d.store)) &&
      (filters.regions.length === 0 || filters.regions.includes(d.region)) &&
      (filters.storeTypes.length === 0 || filters.storeTypes.includes(d.store_type))
    );
    return [...new Set(valid.map(d => d.concept))].sort();
  }, [allData, filters.stores, filters.regions, filters.storeTypes]);

  const availableRegions = React.useMemo(() => {
    const valid = allData.filter(d => 
      (filters.stores.length === 0 || filters.stores.includes(d.store)) &&
      (filters.concepts.length === 0 || filters.concepts.includes(d.concept)) &&
      (filters.storeTypes.length === 0 || filters.storeTypes.includes(d.store_type))
    );
    return [...new Set(valid.map(d => d.region))].sort();
  }, [allData, filters.stores, filters.concepts, filters.storeTypes]);

  const availableStoreTypes = React.useMemo(() => {
    const valid = allData.filter(d => 
      (filters.stores.length === 0 || filters.stores.includes(d.store)) &&
      (filters.concepts.length === 0 || filters.concepts.includes(d.concept)) &&
      (filters.regions.length === 0 || filters.regions.includes(d.region))
    );
    return [...new Set(valid.map(d => d.store_type))].sort();
  }, [allData, filters.stores, filters.concepts, filters.regions]);

  // Apply filters to all data
  const filteredData = React.useMemo(() => {
    let result = allData;

    // Dimension filters
    if (filters.stores.length > 0) {
      result = result.filter(d => filters.stores.includes(d.store));
    }
    if (filters.concepts.length > 0) {
      result = result.filter(d => filters.concepts.includes(d.concept));
    }
    if (filters.regions.length > 0) {
      result = result.filter(d => filters.regions.includes(d.region));
    }
    if (filters.storeTypes.length > 0) {
      result = result.filter(d => filters.storeTypes.includes(d.store_type));
    }
    if (filters.locations.length > 0) {
      result = result.filter(d => filters.locations.includes(d.location));
    }
    if (filters.legalEntities.length > 0) {
      result = result.filter(d => filters.legalEntities.includes(d.legal_entity));
    }

    return result;
  }, [allData, filters]);

  const updateFilter = useCallback(<K extends keyof FilterState>(key: K, value: FilterState[K]) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  }, []);

  const clearFilters = useCallback(() => {
    setFilters(prev => ({
      ...defaultFilters,
      year: prev.year,
      month: prev.month,
    }));
  }, []);

  return (
    <FilterContext.Provider
      value={{
        filters,
        setFilters,
        updateFilter,
        clearFilters,
        availableYears,
        availableStores,
        availableConcepts,
        availableRegions,
        availableStoreTypes,
        availableLocations,
        availableLegalEntities,
        allData,
        filteredData,
        isLoading,
        refreshData,
      }}
    >
      {children}
    </FilterContext.Provider>
  );
}

export function useFilters() {
  const ctx = useContext(FilterContext);
  if (!ctx) throw new Error('useFilters must be used within FilterProvider');
  return ctx;
}

/* ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
 * Calculation Engine ΓÇö YTD, LTM, weighted aggregation
 * ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */

import type {
  StoreMonthRecord,
  StoreMonthWithRatios,
  AggregatedMetrics,
  PeriodBasis,
} from './types';

/** Safe division: returns null if denominator is 0 */
function safeDivide(num: number, den: number): number | null {
  return den !== 0 ? num / den : null;
}

/**
 * Filter records for a given period basis
 */
export function filterByPeriod(
  records: StoreMonthRecord[],
  basis: PeriodBasis,
  year: number,
  month: number,
): StoreMonthRecord[] {
  switch (basis) {
    case 'monthly':
      return records.filter(r => r.year === year && r.month === month);

    case 'ytd':
      return records.filter(r => r.year === year && r.month <= month);

    case 'ltm': {
      // Trailing 12 months ending in year/month
      const endDate = year * 12 + month;
      const startDate = endDate - 11; // 12 months inclusive
      return records.filter(r => {
        const d = r.year * 12 + r.month;
        return d >= startDate && d <= endDate;
      });
    }
  }
}

/**
 * Aggregate records using weighted logic (┬º11.3)
 * Critical: ratio metrics use SUM(metric) / SUM(sales), NOT average of store-level %
 */
export function aggregate(records: StoreMonthRecord[]): AggregatedMetrics {
  const uniqueStores = new Set(records.map(r => r.store));

  const totalSales = records.reduce((s, r) => s + r.sales, 0);
  const totalTickets = records.reduce((s, r) => s + r.tickets, 0);
  const totalRawMaterials = records.reduce((s, r) => s + r.raw_materials, 0);
  const totalStaff = records.reduce((s, r) => s + r.staff, 0);
  const totalRents = records.reduce((s, r) => s + r.rents, 0);
  const totalUtilities = records.reduce((s, r) => s + r.utilities, 0);
  const totalMaintenance = records.reduce((s, r) => s + r.maintenance, 0);
  const totalBankingCosts = records.reduce((s, r) => s + r.banking_costs, 0);
  const totalVat = records.reduce((s, r) => s + r.vat, 0);
  const totalOthers = records.reduce((s, r) => s + r.others, 0);
  const totalSC = records.reduce((s, r) => s + r.store_contribution, 0);
  const totalAdminCosts = records.reduce((s, r) => s + r.admin_costs, 0);
  const totalEbitda = records.reduce((s, r) => s + r.ebitda, 0);
  const totalCapex = records.reduce((s, r) => s + r.capex, 0);
  const totalCit = records.reduce((s, r) => s + r.cit, 0);
  const totalFcff = records.reduce((s, r) => s + r.fcff, 0);

  // Count stores with negative EBITDA / FCFF (for monthly view, use the latest month per store)
  const ebitdaNegativeCount = countNegativeStores(records, 'ebitda');
  const fcffNegativeCount = countNegativeStores(records, 'fcff');

  const storeCount = uniqueStores.size;

  return {
    storeCount,
    totalSales,
    totalTickets,
    avgTicket: safeDivide(totalSales, totalTickets) ?? 0,
    totalRawMaterials,
    totalStaff,
    totalRents,
    totalUtilities,
    totalMaintenance,
    totalBankingCosts,
    totalVat,
    totalOthers,
    totalStoreContribution: totalSC,
    totalAdminCosts,
    totalEbitda,
    totalCapex,
    totalCit,
    totalFcff,
    // Weighted ratios
    rawMaterialsPct: safeDivide(totalRawMaterials, totalSales),
    staffPct: safeDivide(totalStaff, totalSales),
    rentsPct: safeDivide(totalRents, totalSales),
    utilitiesPct: safeDivide(totalUtilities, totalSales),
    maintenancePct: safeDivide(totalMaintenance, totalSales),
    bankingCostsPct: safeDivide(totalBankingCosts, totalSales),
    vatPct: safeDivide(totalVat, totalSales),
    othersPct: safeDivide(totalOthers, totalSales),
    storeContributionPct: safeDivide(totalSC, totalSales),
    adminCostsPct: safeDivide(totalAdminCosts, totalSales),
    ebitdaPct: safeDivide(totalEbitda, totalSales),
    fcffPct: safeDivide(totalFcff, totalSales),
    // Derived
    ebitdaNegativeCount,
    fcffNegativeCount,
    salesPerStore: safeDivide(totalSales, storeCount) ?? 0,
    ebitdaPerStore: safeDivide(totalEbitda, storeCount) ?? 0,
    fcffPerStore: safeDivide(totalFcff, storeCount) ?? 0,
  };
}

/**
 * Aggregate records per store (sum across months, then compute per-store weighted ratios)
 */
export function aggregatePerStore(
  records: StoreMonthRecord[],
): Map<string, AggregatedMetrics & { store: string; concept: string; region: string; store_type: string; location: string; legal_entity: string }> {
  const grouped = new Map<string, StoreMonthRecord[]>();
  for (const r of records) {
    const list = grouped.get(r.store) || [];
    list.push(r);
    grouped.set(r.store, list);
  }

  const result = new Map<string, AggregatedMetrics & { store: string; concept: string; region: string; store_type: string; location: string; legal_entity: string }>();
  for (const [store, storeRecords] of grouped) {
    const agg = aggregate(storeRecords);
    const first = storeRecords[0];
    result.set(store, {
      ...agg,
      store,
      concept: first.concept,
      region: first.region,
      store_type: first.store_type,
      location: first.location,
      legal_entity: first.legal_entity,
    });
  }
  return result;
}

/**
 * Aggregate records per segment dimension
 */
export function aggregateByDimension(
  records: StoreMonthRecord[],
  dimension: 'concept' | 'region' | 'store_type' | 'location' | 'legal_entity',
): Map<string, AggregatedMetrics> {
  const grouped = new Map<string, StoreMonthRecord[]>();
  for (const r of records) {
    const key = r[dimension];
    const list = grouped.get(key) || [];
    list.push(r);
    grouped.set(key, list);
  }

  const result = new Map<string, AggregatedMetrics>();
  for (const [key, recs] of grouped) {
    result.set(key, aggregate(recs));
  }
  return result;
}

/**
 * Count stores with negative metric value (aggregate per store first)
 */
function countNegativeStores(records: StoreMonthRecord[], metric: 'ebitda' | 'fcff'): number {
  const storeAggs = new Map<string, number>();
  for (const r of records) {
    storeAggs.set(r.store, (storeAggs.get(r.store) || 0) + r[metric]);
  }
  let count = 0;
  for (const val of storeAggs.values()) {
    if (val < 0) count++;
  }
  return count;
}

/**
 * Get monthly trend data: one data point per year-month combination
 */
export function getMonthlyTrend(
  records: StoreMonthRecord[],
  metric: keyof Pick<StoreMonthRecord, 'sales' | 'tickets' | 'avg_ticket' | 'ebitda' | 'fcff' | 'raw_materials' | 'staff' | 'store_contribution'>,
): Array<{ period: string; year: number; month: number; value: number; sales: number }> {
  const grouped = new Map<string, StoreMonthRecord[]>();
  for (const r of records) {
    const key = `${r.year}-${String(r.month).padStart(2, '0')}`;
    const list = grouped.get(key) || [];
    list.push(r);
    grouped.set(key, list);
  }

  return Array.from(grouped.entries())
    .map(([period, recs]) => {
      const totalSales = recs.reduce((s, r) => s + r.sales, 0);
      const totalTickets = recs.reduce((s, r) => s + r.tickets, 0);
      let value: number;
      if (metric === 'avg_ticket') {
        value = totalTickets !== 0 ? totalSales / totalTickets : 0;
      } else {
        value = recs.reduce((s, r) => s + (r[metric] as number), 0);
      }
      return {
        period,
        year: recs[0].year,
        month: recs[0].month,
        value,
        sales: totalSales,
      };
    })
    .sort((a, b) => a.period.localeCompare(b.period));
}

/**
 * Get ratio trend data (weighted aggregation per period)
 */
export function getRatioTrend(
  records: StoreMonthRecord[],
  numeratorField: keyof Pick<StoreMonthRecord, 'raw_materials' | 'staff' | 'rents' | 'ebitda' | 'fcff' | 'store_contribution'>,
  denominatorField: keyof Pick<StoreMonthRecord, 'sales' | 'tickets'> = 'sales',
): Array<{ period: string; year: number; month: number; value: number | null }> {
  const grouped = new Map<string, StoreMonthRecord[]>();
  for (const r of records) {
    const key = `${r.year}-${String(r.month).padStart(2, '0')}`;
    const list = grouped.get(key) || [];
    list.push(r);
    grouped.set(key, list);
  }

  return Array.from(grouped.entries())
    .map(([period, recs]) => {
      const totalNum = recs.reduce((s, r) => s + (r[numeratorField] as number), 0);
      const totalDen = recs.reduce((s, r) => s + (r[denominatorField] as number), 0);
      return {
        period,
        year: recs[0].year,
        month: recs[0].month,
        value: safeDivide(totalNum, totalDen),
      };
    })
    .sort((a, b) => a.period.localeCompare(b.period));
}

/* ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
 * Excel Parser ΓÇö converts uploaded .xlsx into StoreMonthRecord[]
 * ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */

import * as XLSX from 'xlsx';
import { EXCEL_COLUMN_MAP, SKIP_COLUMNS, MONTH_NAME_TO_NUMBER } from './constants';
import type { StoreMonthRecord } from './types';

export interface ParseResult {
  records: StoreMonthRecord[];
  errors: string[];
  skippedRows: number;
}

/**
 * Parse an Excel file buffer into StoreMonthRecord[]
 * Expects a flat table with headers in row 1 matching EXCEL_COLUMN_MAP keys.
 */
export function parseExcelFile(buffer: ArrayBuffer, filename: string): ParseResult {
  const errors: string[] = [];
  let skippedRows = 0;

  const wb = XLSX.read(buffer, { type: 'array' });
  const sheetName = wb.SheetNames[0];
  if (!sheetName) {
    return { records: [], errors: ['No sheets found in workbook'], skippedRows: 0 };
  }

  const ws = wb.Sheets[sheetName];
  const rawData: Record<string, unknown>[] = XLSX.utils.sheet_to_json(ws, { defval: null });

  if (rawData.length === 0) {
    return { records: [], errors: ['Sheet is empty'], skippedRows: 0 };
  }

  // Validate headers
  const headers = Object.keys(rawData[0]);
  const requiredHeaders = ['Store', 'Year', 'Month', 'Sales'];
  const missing = requiredHeaders.filter(h => !headers.includes(h));
  if (missing.length > 0) {
    errors.push(`Missing required columns: ${missing.join(', ')}`);
    return { records: [], errors, skippedRows: 0 };
  }

  const records: StoreMonthRecord[] = [];

  for (let i = 0; i < rawData.length; i++) {
    const row = rawData[i];
    const rowNum = i + 2; // 1-indexed, accounting for header

    // Build the record by mapping Excel columns ΓåÆ DB fields
    const record: Record<string, unknown> = {};
    let hasData = false;

    for (const [excelCol, value] of Object.entries(row)) {
      // Skip percentage columns
      if (SKIP_COLUMNS.has(excelCol)) continue;

      const dbField = EXCEL_COLUMN_MAP[excelCol];
      if (!dbField) continue; // Unknown column, skip

      if (dbField === 'month') {
        // Convert month name to number
        const monthStr = String(value ?? '').toLowerCase().trim();
        const monthNum = MONTH_NAME_TO_NUMBER[monthStr];
        if (!monthNum) {
          errors.push(`Row ${rowNum}: Invalid month "${value}"`);
          continue;
        }
        record[dbField] = monthNum;
      } else if (['store', 'concept', 'region', 'store_type', 'location', 'legal_entity'].includes(dbField)) {
        record[dbField] = String(value ?? '').trim();
      } else {
        // Numeric field
        const num = Number(value);
        if (isNaN(num)) {
          record[dbField] = 0;
        } else {
          record[dbField] = num;
          if (dbField !== 'year' && num !== 0) hasData = true;
        }
      }
    }

    // Validate required fields
    if (!record.store || !record.year || !record.month) {
      errors.push(`Row ${rowNum}: Missing store, year, or month`);
      skippedRows++;
      continue;
    }

    // Auto-correct corrupted spreadsheet formulas
    // If Tickets > Sales, it implies Avg Ticket < Γé¼1, which is practically impossible.
    // This usually means the spreadsheet formula mistakenly did: Tickets = Sales * AvgTicket
    if ((record.tickets as number) > (record.sales as number) && (record.avg_ticket as number) > 0) {
      record.tickets = (record.sales as number) / (record.avg_ticket as number);
    }

    // Skip rows with no actual data
    if (!hasData) {
      skippedRows++;
      continue;
    }

    // Fill defaults for missing optional fields
    record.concept = record.concept || 'Unknown';
    record.region = record.region || 'Unknown';
    record.store_type = record.store_type || 'Unknown';
    record.location = record.location || 'Unknown';
    record.legal_entity = record.legal_entity || 'Unknown';

    records.push(record as unknown as StoreMonthRecord);
  }

  // Deduplicate records by store, year, month (keep the last occurrence)
  const dedupedRecords: StoreMonthRecord[] = [];
  const seenKeys = new Set<string>();

  // Go backwards to keep the last occurrence easily
  for (let i = records.length - 1; i >= 0; i--) {
    const r = records[i];
    const key = `${r.store}-${r.year}-${r.month}`;
    if (!seenKeys.has(key)) {
      seenKeys.add(key);
      dedupedRecords.unshift(r);
    }
  }

  return { records: dedupedRecords, errors, skippedRows };
}
